public class FilterConfiguration implements WebMvcConfigurer {

    @Bean
    public FilterRegistrationBean wmPlatformCookieFilter() {
        FilterRegistrationBean filterRegistration = new FilterRegistrationBean();
        filterRegistration.setName("wmPlatformCookieFilter");
        filterRegistration.setFilter(new WmPlatformCookieFilter());
        filterRegistration.addUrlPatterns("/*");
        return filterRegistration;
    }

    @Bean
    public FilterRegistrationBean infFilter() {
        FilterRegistrationBean filterRegistration = new FilterRegistrationBean();
        filterRegistration.setName("infFilter");
        filterRegistration.setFilter(new InfFilter());
        filterRegistration.addInitParameter("auth", "false");
        filterRegistration.addInitParameter("limit", "true");
        filterRegistration.addInitParameter("rehearse", "true");
        filterRegistration.addInitParameter("oceanus-http.inffilter.auth-include-uri", "/ad/**");
        filterRegistration.addInitParameter("oceanus-http.inffilter.auth-exclude-uri", "/status/**,/ad/v1/static/**,/ad/v1/pay/notify/**,/ad/v1/ka/order/preview/**,/ad/banner/landing/**,/onlinepay/refund/**");
        filterRegistration.addUrlPatterns("/ad/*");
        return filterRegistration;
    }

}

